'use client';

/**
 * Tab de Relatórios - Relatórios e Analytics
 */

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useCRM } from '@/hooks/useCRM';
import {
    BarChart3,
    Download,
    FileText,
    TrendingUp,
    Users,
    DollarSign,
    Calendar,
    PieChart,
} from 'lucide-react';
import { formatCurrency } from '@/lib/currency';
import { PIPELINE_STAGES } from '@/types/crm';

export function ReportsTab() {
    const { deals, contacts, isLoading } = useCRM();

    // Métricas para relatório
    const totalDeals = deals.length;
    const totalContacts = contacts.length;
    const totalValue = deals.reduce((sum, d) => sum + (d.value || 0), 0);

    // Deals por stage
    const dealsByStage = PIPELINE_STAGES.map(stage => ({
        ...stage,
        count: deals.filter(d => d.stage === stage.value).length,
        value: deals.filter(d => d.stage === stage.value).reduce((sum, d) => sum + (d.value || 0), 0),
    }));

    // Deals convertidos
    const convertedStages = ['em_tratamento', 'finalizado', 'fechado_ganho'];
    const convertedDeals = deals.filter(d => convertedStages.includes(d.stage));
    const conversionRate = totalDeals > 0 ? ((convertedDeals.length / totalDeals) * 100).toFixed(1) : '0';

    if (isLoading) {
        return (
            <div className="space-y-4 animate-pulse">
                <div className="h-24 bg-muted rounded-lg" />
                <div className="h-64 bg-muted rounded-lg" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <Users className="h-4 w-4 text-muted-foreground" />
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Contatos
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-2xl font-bold">{totalContacts}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <FileText className="h-4 w-4 text-muted-foreground" />
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Deals
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-2xl font-bold">{totalDeals}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <DollarSign className="h-4 w-4 text-muted-foreground" />
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Valor Total
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-2xl font-bold">{formatCurrency(totalValue)}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <TrendingUp className="h-4 w-4 text-muted-foreground" />
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Conversão
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-2xl font-bold">{conversionRate}%</p>
                    </CardContent>
                </Card>
            </div>

            {/* Report Types */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                <Card className="cursor-pointer hover:border-primary/50 transition-colors">
                    <CardHeader>
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-blue-500/10">
                                <PieChart className="h-5 w-5 text-blue-500" />
                            </div>
                            <div>
                                <CardTitle className="text-base">Relatório de Pipeline</CardTitle>
                                <CardDescription>Distribuição por etapa</CardDescription>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            {dealsByStage.slice(0, 4).map(stage => (
                                <div key={stage.value} className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">{stage.label}</span>
                                    <span className="font-medium">{stage.count}</span>
                                </div>
                            ))}
                        </div>
                        <Button variant="outline" className="w-full mt-4" size="sm">
                            <Download className="h-4 w-4 mr-2" />
                            Exportar
                        </Button>
                    </CardContent>
                </Card>

                <Card className="cursor-pointer hover:border-primary/50 transition-colors">
                    <CardHeader>
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-green-500/10">
                                <DollarSign className="h-5 w-5 text-green-500" />
                            </div>
                            <div>
                                <CardTitle className="text-base">Relatório Financeiro</CardTitle>
                                <CardDescription>Receitas e valores</CardDescription>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            <div className="flex items-center justify-between text-sm">
                                <span className="text-muted-foreground">Valor em Pipeline</span>
                                <span className="font-medium">{formatCurrency(totalValue)}</span>
                            </div>
                            <div className="flex items-center justify-between text-sm">
                                <span className="text-muted-foreground">Valor Convertido</span>
                                <span className="font-medium text-green-600">
                                    {formatCurrency(convertedDeals.reduce((s, d) => s + (d.value || 0), 0))}
                                </span>
                            </div>
                        </div>
                        <Button variant="outline" className="w-full mt-4" size="sm">
                            <Download className="h-4 w-4 mr-2" />
                            Exportar
                        </Button>
                    </CardContent>
                </Card>

                <Card className="cursor-pointer hover:border-primary/50 transition-colors">
                    <CardHeader>
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-purple-500/10">
                                <Calendar className="h-5 w-5 text-purple-500" />
                            </div>
                            <div>
                                <CardTitle className="text-base">Relatório de Período</CardTitle>
                                <CardDescription>Análise temporal</CardDescription>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-sm text-muted-foreground mb-4">
                            Selecione um período para gerar o relatório detalhado de atividades.
                        </p>
                        <Button variant="outline" className="w-full" size="sm">
                            <BarChart3 className="h-4 w-4 mr-2" />
                            Gerar Relatório
                        </Button>
                    </CardContent>
                </Card>
            </div>

            {/* Export Actions */}
            <Card>
                <CardHeader>
                    <CardTitle>Exportar Dados</CardTitle>
                    <CardDescription>
                        Exporte seus dados para análise externa
                    </CardDescription>
                </CardHeader>
                <CardContent className="flex gap-3">
                    <Button variant="outline">
                        <Download className="h-4 w-4 mr-2" />
                        Exportar Contatos (CSV)
                    </Button>
                    <Button variant="outline">
                        <Download className="h-4 w-4 mr-2" />
                        Exportar Deals (CSV)
                    </Button>
                    <Button variant="outline">
                        <Download className="h-4 w-4 mr-2" />
                        Relatório Completo (PDF)
                    </Button>
                </CardContent>
            </Card>
        </div>
    );
}
