'use client';

/**
 * Tab de Leads - Gestão de Leads e Conversões
 */

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { useCRM } from '@/hooks/useCRM';
import {
    Search,
    Plus,
    Phone,
    Mail,
    MessageCircle,
    TrendingUp,
    Filter,
    MoreVertical,
    Calendar,
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { formatCurrency } from '@/lib/currency';
import { PIPELINE_STAGES, ALL_PIPELINE_STAGES } from '@/types/crm';

export function LeadsTab() {
    const { deals, contacts, isLoading } = useCRM();
    const [searchQuery, setSearchQuery] = useState('');
    const [stageFilter, setStageFilter] = useState<string | null>(null);

    // Filtrar deals (leads são deals nos estágios iniciais)
    const leadStages = ['lead_novo', 'em_contato', 'qualificado'];
    const leads = deals.filter(deal => {
        const isLead = leadStages.includes(deal.stage);
        const matchesSearch = !searchQuery ||
            deal.title?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            deal.contact?.full_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            deal.contact?.phone?.includes(searchQuery);
        const matchesStage = !stageFilter || deal.stage === stageFilter;
        return isLead && matchesSearch && matchesStage;
    });

    // Métricas
    const totalLeads = leads.length;
    const newLeadsToday = leads.filter(l => {
        if (!l.created_at) return false;
        const today = new Date();
        const created = new Date(l.created_at);
        return created.toDateString() === today.toDateString();
    }).length;
    const totalValue = leads.reduce((sum, l) => sum + (l.value || 0), 0);

    const getStageInfo = (stage: string) => {
        return ALL_PIPELINE_STAGES.find(s => s.value === stage) || PIPELINE_STAGES[0];
    };

    if (isLoading) {
        return (
            <div className="space-y-4 animate-pulse">
                <div className="h-24 bg-muted rounded-lg" />
                <div className="h-64 bg-muted rounded-lg" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Total de Leads
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">{totalLeads}</p>
                        <p className="text-xs text-muted-foreground mt-1">
                            +{newLeadsToday} hoje
                        </p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Valor Potencial
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">{formatCurrency(totalValue)}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Taxa de Qualificação
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">
                            {totalLeads > 0
                                ? ((leads.filter(l => l.stage !== 'lead_novo').length / totalLeads) * 100).toFixed(0)
                                : 0}%
                        </p>
                    </CardContent>
                </Card>
            </div>

            {/* Actions */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex gap-3">
                    <Button>
                        <Plus className="w-4 h-4 mr-2" />
                        Novo Lead
                    </Button>
                </div>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar leads..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="pl-9"
                        />
                    </div>
                    <Button variant="outline">
                        <Filter className="w-4 h-4 mr-2" />
                        Filtros
                    </Button>
                </div>
            </div>

            {/* Leads List */}
            <Card>
                <CardHeader>
                    <CardTitle>Lista de Leads</CardTitle>
                    <CardDescription>
                        Gerencie seus leads e acompanhe o progresso de conversão
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    {leads.length === 0 ? (
                        <div className="text-center py-12 text-muted-foreground">
                            <TrendingUp className="h-12 w-12 mx-auto mb-4 opacity-50" />
                            <p>Nenhum lead encontrado</p>
                            <p className="text-sm">Adicione novos leads para começar a acompanhar</p>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {leads.map((lead) => {
                                const stageInfo = getStageInfo(lead.stage);
                                const initials = lead.contact?.full_name
                                    ?.split(' ')
                                    .map(n => n[0])
                                    .join('')
                                    .substring(0, 2)
                                    .toUpperCase() || 'LD';

                                return (
                                    <div
                                        key={lead.id}
                                        className="flex items-center justify-between p-4 rounded-lg border hover:bg-muted/50 transition-colors"
                                    >
                                        <div className="flex items-center gap-4">
                                            <Avatar>
                                                <AvatarFallback className={stageInfo.bgColor}>
                                                    {initials}
                                                </AvatarFallback>
                                            </Avatar>
                                            <div>
                                                <p className="font-medium">
                                                    {lead.contact?.full_name || lead.title}
                                                </p>
                                                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                                    {lead.contact?.phone && (
                                                        <span className="flex items-center gap-1">
                                                            <Phone className="h-3 w-3" />
                                                            {lead.contact.phone}
                                                        </span>
                                                    )}
                                                    {lead.contact?.email && (
                                                        <span className="flex items-center gap-1">
                                                            <Mail className="h-3 w-3" />
                                                            {lead.contact.email}
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-4">
                                            <Badge variant="secondary" className={stageInfo.bgColor}>
                                                {stageInfo.label}
                                            </Badge>
                                            {lead.value && (
                                                <span className="text-sm font-medium">
                                                    {formatCurrency(lead.value)}
                                                </span>
                                            )}
                                            {lead.created_at && (
                                                <span className="text-xs text-muted-foreground">
                                                    {formatDistanceToNow(new Date(lead.created_at), {
                                                        addSuffix: true,
                                                        locale: ptBR,
                                                    })}
                                                </span>
                                            )}
                                            <div className="flex items-center gap-1">
                                                <Button variant="ghost" size="icon" className="h-8 w-8">
                                                    <Phone className="h-4 w-4" />
                                                </Button>
                                                <Button variant="ghost" size="icon" className="h-8 w-8">
                                                    <MessageCircle className="h-4 w-4" />
                                                </Button>
                                                <Button variant="ghost" size="icon" className="h-8 w-8">
                                                    <Calendar className="h-4 w-4" />
                                                </Button>
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}
