'use client'

import { useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { AnimatedDealCard } from "./AnimatedDealCard";
import { FollowUpSection } from "./FollowUpSection";
import { CRMDealWithContact, CRMPipelineStage, PIPELINE_STAGES } from "@/types/crm";
import { FollowUp } from "@/types/followUp";
import { Users } from "lucide-react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { ContactActionSelector } from "./ContactActionSelector";
import { formatCurrency } from "@/lib/currency";
import { useUserProfile } from "@/hooks/useUserProfile";
import {
    DndContext,
    DragEndEvent,
    DragOverEvent,
    DragStartEvent,
    PointerSensor,
    KeyboardSensor,
    useSensor,
    useSensors,
    DragOverlay,
    closestCenter,
    useDroppable,
    MeasuringStrategy,
} from "@dnd-kit/core";
import {
    SortableContext,
    verticalListSortingStrategy,
    arrayMove,
    sortableKeyboardCoordinates,
    useSortable,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";

interface SortableDealCardProps {
    deal: CRMDealWithContact;
    onClick?: () => void;
    onEdit?: (deal: CRMDealWithContact) => void;
    onDelete?: (dealId: string) => void;
    onScheduleCall?: (deal: CRMDealWithContact) => void;
    isDeleting?: boolean;
    isHighlighted?: boolean;
    onToggleFollowUp?: (dealId: string, needsFollowUp: boolean) => void;
    showOwnerBadge?: boolean;
}

function SortableDealCard({
    deal,
    onClick,
    onEdit,
    onDelete,
    onScheduleCall,
    isDeleting,
    isHighlighted,
    onToggleFollowUp,
    showOwnerBadge
}: SortableDealCardProps) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging,
    } = useSortable({
        id: deal.id,
        data: {
            type: 'deal',
            deal,
        }
    });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition: isDragging ? 'none' : (transition || 'transform 80ms ease-out'),
        opacity: isDragging ? 0.5 : 1,
        cursor: isDragging ? 'grabbing' : 'grab',
        zIndex: isDragging ? 1000 : 'auto',
        willChange: isDragging ? 'transform' : 'auto',
    };

    return (
        <div
            ref={setNodeRef}
            style={{
                ...style,
                width: '100%',
                maxWidth: '100%',
                boxSizing: 'border-box',
                overflow: 'visible',
                touchAction: 'none',
                margin: 0,
                position: 'relative',
                padding: '2px',
            }}
            {...attributes}
            {...listeners}
        >
            <AnimatedDealCard
                deal={deal}
                onClick={onClick}
                onEdit={onEdit}
                onDelete={onDelete}
                onScheduleCall={onScheduleCall}
                isDeleting={isDeleting}
                isHighlighted={isHighlighted}
                onToggleFollowUp={onToggleFollowUp}
                showOwnerBadge={showOwnerBadge}
            />
        </div>
    );
}

export interface PipelineBoardProps {
    deals: CRMDealWithContact[];
    followUps?: FollowUp[];
    onDealClick?: (deal: CRMDealWithContact) => void;
    onStageClick?: (stage: string) => void;
    onUpdateDeal?: (dealId: string, stage: CRMPipelineStage, position?: number) => void;
    onReorderDealsInStage?: (stage: string, dealIds: string[]) => Promise<void>;
    onEditDeal?: (deal: CRMDealWithContact) => void;
    onDeleteDeal?: (dealId: string) => void;
    onScheduleCall?: (deal: CRMDealWithContact) => void;
    isDeletingDeal?: boolean;
    onCall?: (deal: CRMDealWithContact) => void;
    onEmail?: (deal: CRMDealWithContact) => void;
    onWhatsApp?: (deal: CRMDealWithContact) => void;
    onContactAdded?: (dealId: string) => void;
    highlightedDealId?: string | null;
    onToggleFollowUp?: (dealId: string, needsFollowUp: boolean) => void;
    onCompleteFollowUp?: (followUpId: string) => void;
    onEditFollowUp?: (followUp: FollowUp) => void;
    showOwnerBadge?: boolean;
}

export function PipelineBoard({
    deals,
    followUps = [],
    onDealClick,
    onUpdateDeal,
    onReorderDealsInStage,
    onEditDeal,
    onDeleteDeal,
    onScheduleCall,
    isDeletingDeal,
    onContactAdded,
    highlightedDealId,
    onToggleFollowUp,
    onCompleteFollowUp,
    onEditFollowUp,
    showOwnerBadge,
}: PipelineBoardProps) {
    const { isSecretaria } = useUserProfile();
    const [activeDeal, setActiveDeal] = useState<CRMDealWithContact | null>(null);

    const sensors = useSensors(
        useSensor(PointerSensor, {
            activationConstraint: {
                distance: 3,
                tolerance: 5,
            },
        }),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates,
        })
    );

    const measuringConfig = {
        droppable: {
            strategy: MeasuringStrategy.Always,
        },
    };

    const dealsByStage = useMemo(() => {
        const grouped: Record<string, CRMDealWithContact[]> = {};
        PIPELINE_STAGES.forEach(stage => {
            grouped[stage.value] = [];
        });

        deals.forEach(deal => {
            if (grouped[deal.stage!]) {
                grouped[deal.stage!].push(deal);
            }
        });

        Object.keys(grouped).forEach(stage => {
            grouped[stage].sort((a, b) => (a.position || 0) - (b.position || 0));
        });

        return grouped;
    }, [deals]);

    const totalsByStage = useMemo(() => {
        const totals: Record<string, string> = {};
        PIPELINE_STAGES.forEach(stage => {
            const stageDeals = dealsByStage[stage.value] || [];
            const total = stageDeals.reduce((sum, deal) => {
                const value = typeof deal.value === 'string' ? parseFloat(deal.value) : deal.value;
                return sum + (value || 0);
            }, 0);
            totals[stage.value] = formatCurrency(total);
        });
        return totals;
    }, [dealsByStage]);

    const uniqueContactsByStage = useMemo(() => {
        const counts: Record<string, number> = {};
        PIPELINE_STAGES.forEach(stage => {
            const stageDeals = dealsByStage[stage.value] || [];
            const uniqueContacts = new Set(stageDeals.map(deal => deal.contact_id).filter(Boolean));
            counts[stage.value] = uniqueContacts.size;
        });
        return counts;
    }, [dealsByStage]);

    const getDealsByStage = (stage: string) => dealsByStage[stage] || [];
    const getTotalValueByStage = (stage: string) => totalsByStage[stage] || formatCurrency(0);
    const getUniqueContactsByStage = (stage: string) => uniqueContactsByStage[stage] || 0;

    const handleDragStart = (event: DragStartEvent) => {
        const { active } = event;
        const deal = deals.find(d => d.id === active.id);
        if (deal) setActiveDeal(deal);
    };

    const handleDragEnd = async (event: DragEndEvent) => {
        const { active, over } = event;
        setActiveDeal(null);

        if (!over || active.id === over.id || !onUpdateDeal) return;

        const activeId = active.id as string;
        const activeDeal = deals.find(d => d.id === activeId);
        if (!activeDeal) return;

        const overIsStage = PIPELINE_STAGES.some(s => s.value === over.id);
        let targetStage: CRMPipelineStage;

        if (overIsStage) {
            targetStage = over.id as CRMPipelineStage;
        } else {
            const overDeal = deals.find(d => d.id === over.id);
            if (!overDeal) return;
            targetStage = overDeal.stage!;
        }

        if (activeDeal.stage === targetStage) {
            const stageDeals = getDealsByStage(targetStage);
            const oldIndex = stageDeals.findIndex(d => d.id === activeId);
            const newIndex = stageDeals.findIndex(d => d.id === over.id);

            if (oldIndex !== newIndex && oldIndex >= 0 && newIndex >= 0) {
                const reordered = arrayMove(stageDeals, oldIndex, newIndex);
                if (onReorderDealsInStage) {
                    const reorderedIds = reordered.map(d => d.id);
                    await onReorderDealsInStage(targetStage, reorderedIds);
                }
            }
            return;
        }

        try {
            await onUpdateDeal(activeId, targetStage);
        } catch (error) {
            console.error('Erro ao atualizar deal:', error);
        }
    };

    function DroppableColumn({ stage, children }: { stage: typeof PIPELINE_STAGES[0], children: React.ReactNode }) {
        const { setNodeRef, isOver } = useDroppable({
            id: stage.value,
            data: { type: 'column', stage: stage.value }
        });
        return (
            <Card
                ref={setNodeRef}
                className={`flex-shrink-0 w-80 bg-gradient-to-br from-card to-card/50 border-2 shadow-card transition-all duration-100 ease-out ${isOver
                    ? 'border-primary shadow-glow ring-2 ring-primary/20 scale-[1.01]'
                    : 'border-border hover:shadow-lg'
                    }`}
                style={{
                    width: '320px',
                    maxWidth: '320px',
                    minWidth: '320px',
                    boxSizing: 'border-box',
                    overflow: 'hidden',
                    transform: 'translateZ(0)',
                    willChange: isOver ? 'transform, box-shadow' : 'auto',
                }}
            >
                {children}
            </Card>
        );
    }

    return (
        <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragStart={handleDragStart}
            onDragEnd={handleDragEnd}
            measuring={measuringConfig}
        >
            <div className="flex gap-4 overflow-x-auto pb-4">
                {PIPELINE_STAGES.map((stage) => {
                    const stageDeals = getDealsByStage(stage.value);

                    return (
                        <DroppableColumn key={stage.value} stage={stage}>
                            <CardHeader className="pb-3 bg-gradient-to-r from-transparent to-primary/5 rounded-t-lg">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className={`flex items-center justify-center w-12 h-12 rounded-xl ${stage.bgColor} border border-border/50 shadow-sm`}>
                                            <stage.icon className={`w-6 h-6 ${stage.textColor}`} />
                                        </div>
                                        <div>
                                            <CardTitle className="text-base font-semibold text-foreground h-12 flex items-center leading-tight">
                                                {stage.label}
                                            </CardTitle>
                                            {!isSecretaria && (
                                                <p className="text-sm text-muted-foreground mt-0.5 font-medium">
                                                    {getTotalValueByStage(stage.value)}
                                                </p>
                                            )}
                                            <div className="flex items-center gap-3 mt-1">
                                                <div className="flex items-center gap-1 text-xs text-muted-foreground">
                                                    <Users className="w-3 h-3" />
                                                    <span>{getUniqueContactsByStage(stage.value)} contatos</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    <Badge variant="secondary" className={`text-sm ${stage.bgColor} ${stage.textColor} border-0 font-semibold px-3 py-1.5 rounded-lg`}>
                                        {stageDeals.length}
                                    </Badge>
                                </div>
                            </CardHeader>
                            <CardContent className="p-2 pt-0" style={{ width: '100%', maxWidth: '100%', boxSizing: 'border-box', overflow: 'visible' }}>
                                <ScrollArea className="h-[calc(100vh-300px)] w-full" style={{ width: '100%', maxWidth: '100%', boxSizing: 'border-box' }}>
                                    <SortableContext items={stageDeals.map(deal => deal.id)} strategy={verticalListSortingStrategy}>
                                        <div className="space-y-3 w-full px-1" style={{ width: '100%', maxWidth: '100%', boxSizing: 'border-box', overflow: 'visible' }}>
                                            {stageDeals.map((deal) => (
                                                <SortableDealCard
                                                    key={deal.id}
                                                    deal={deal}
                                                    onClick={() => onDealClick?.(deal)}
                                                    onEdit={onEditDeal}
                                                    onDelete={onDeleteDeal}
                                                    onScheduleCall={onScheduleCall}
                                                    isDeleting={isDeletingDeal}
                                                    isHighlighted={highlightedDealId === deal.id}
                                                    onToggleFollowUp={onToggleFollowUp}
                                                    showOwnerBadge={showOwnerBadge}
                                                />
                                            ))}
                                            {stageDeals.length === 0 && (
                                                <div className="text-center py-8 text-sm text-muted-foreground">
                                                    Nenhum contato nesta etapa
                                                </div>
                                            )}
                                        </div>
                                    </SortableContext>
                                </ScrollArea>
                                <ContactActionSelector
                                    stage={stage.value}
                                    stageConfig={{ bgColor: stage.bgColor, textColor: stage.textColor, label: stage.label }}
                                    onContactAdded={onContactAdded}
                                />
                            </CardContent>
                        </DroppableColumn>
                    );
                })}
                <FollowUpSection
                    deals={deals}
                    followUps={followUps}
                    onDealClick={onDealClick}
                    onCompleteFollowUp={onCompleteFollowUp}
                    onEditFollowUp={onEditFollowUp}
                />
            </div>
            <DragOverlay dropAnimation={{ duration: 150, easing: 'cubic-bezier(0.18, 0.67, 0.6, 1.22)' }} style={{ zIndex: 9999 }} wrapperElement="div">
                {activeDeal ? (
                    <div className="rotate-1" style={{ width: '300px' }}>
                        <AnimatedDealCard
                            deal={activeDeal}
                            isHighlighted={true}
                            showOwnerBadge={showOwnerBadge}
                        />
                    </div>
                ) : null}
            </DragOverlay>
        </DndContext>
    );
}
