'use client';

/**
 * Tab de Vendas - Gestão de Vendas e Procedimentos
 */

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useCRM } from '@/hooks/useCRM';
import {
    ShoppingCart,
    Plus,
    DollarSign,
    TrendingUp,
    Package,
    Calendar,
} from 'lucide-react';
import { formatCurrency } from '@/lib/currency';

export function SalesTab() {
    const { deals, isLoading } = useCRM();

    // Deals convertidos (em tratamento ou finalizados)
    const salesStages = ['em_tratamento', 'finalizado', 'fechado_ganho'];
    const sales = deals.filter(d => salesStages.includes(d.stage));

    // Métricas
    const totalSales = sales.length;
    const totalRevenue = sales.reduce((sum, s) => sum + (s.value || 0), 0);
    const avgTicket = totalSales > 0 ? totalRevenue / totalSales : 0;

    if (isLoading) {
        return (
            <div className="space-y-4 animate-pulse">
                <div className="h-24 bg-muted rounded-lg" />
                <div className="h-64 bg-muted rounded-lg" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Total de Vendas
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">{totalSales}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Receita Total
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">{formatCurrency(totalRevenue)}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Ticket Médio
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">{formatCurrency(avgTicket)}</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Em Tratamento
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">
                            {deals.filter(d => d.stage === 'em_tratamento').length}
                        </p>
                    </CardContent>
                </Card>
            </div>

            {/* Actions */}
            <div className="flex gap-3">
                <Button>
                    <Plus className="w-4 h-4 mr-2" />
                    Nova Venda
                </Button>
                <Button variant="outline">
                    <Package className="w-4 h-4 mr-2" />
                    Catálogo de Procedimentos
                </Button>
            </div>

            {/* Sales List */}
            <Card>
                <CardHeader>
                    <CardTitle>Vendas Recentes</CardTitle>
                    <CardDescription>
                        Acompanhe as vendas e procedimentos em andamento
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    {sales.length === 0 ? (
                        <div className="text-center py-12 text-muted-foreground">
                            <ShoppingCart className="h-12 w-12 mx-auto mb-4 opacity-50" />
                            <p>Nenhuma venda registrada</p>
                            <p className="text-sm">Converta leads para registrar vendas</p>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {sales.slice(0, 10).map((sale) => (
                                <div
                                    key={sale.id}
                                    className="flex items-center justify-between p-4 rounded-lg border hover:bg-muted/50 transition-colors"
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="p-2 rounded-lg bg-green-500/10">
                                            <DollarSign className="h-5 w-5 text-green-500" />
                                        </div>
                                        <div>
                                            <p className="font-medium">
                                                {sale.contact?.full_name || sale.title}
                                            </p>
                                            <p className="text-sm text-muted-foreground">
                                                {sale.title}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="font-medium text-green-600">
                                            {formatCurrency(sale.value || 0)}
                                        </p>
                                        {sale.created_at && (
                                            <p className="text-xs text-muted-foreground">
                                                {new Date(sale.created_at).toLocaleDateString('pt-BR')}
                                            </p>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}
