'use client';

/**
 * Tab de Dashboard - Métricas e KPIs
 */

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { useCRM } from '@/hooks/useCRM';
import {
    Users,
    TrendingUp,
    DollarSign,
    Calendar,
    Target,
    Clock,
    CheckCircle,
    AlertTriangle,
} from 'lucide-react';
import { formatCurrency } from '@/lib/currency';
import { PIPELINE_STAGES } from '@/types/crm';

export function DashboardTab() {
    const { deals, contacts, isLoading } = useCRM();

    // Calcular métricas
    const totalDeals = deals.length;
    const totalContacts = contacts.length;
    const totalValue = deals.reduce((sum, deal) => sum + (deal.value || 0), 0);

    // Deals por stage
    const dealsByStage = PIPELINE_STAGES.map(stage => ({
        ...stage,
        count: deals.filter(d => d.stage === stage.value).length,
        value: deals.filter(d => d.stage === stage.value).reduce((sum, d) => sum + (d.value || 0), 0),
    }));

    // Conversão (deals em tratamento + finalizados / total)
    const convertedDeals = deals.filter(d =>
        d.stage === 'em_tratamento' || d.stage === 'finalizado' || d.stage === 'fechado_ganho'
    ).length;
    const conversionRate = totalDeals > 0 ? ((convertedDeals / totalDeals) * 100).toFixed(1) : '0';

    // Deals em risco (inadimplentes)
    const riskyDeals = deals.filter(d => d.stage === 'inadimplente').length;

    if (isLoading) {
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 animate-pulse">
                {[...Array(8)].map((_, i) => (
                    <Card key={i}>
                        <CardHeader className="pb-2">
                            <div className="h-4 bg-muted rounded w-24" />
                        </CardHeader>
                        <CardContent>
                            <div className="h-8 bg-muted rounded w-16" />
                        </CardContent>
                    </Card>
                ))}
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card className="bg-gradient-to-br from-blue-50 to-blue-100/50 dark:from-blue-950/30 dark:to-blue-900/20 border-blue-200/50">
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <Users className="h-5 w-5 text-blue-600" />
                            <CardTitle className="text-sm font-medium text-blue-700 dark:text-blue-400">
                                Total de Contatos
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold text-blue-700 dark:text-blue-300">
                            {totalContacts}
                        </p>
                    </CardContent>
                </Card>

                <Card className="bg-gradient-to-br from-green-50 to-green-100/50 dark:from-green-950/30 dark:to-green-900/20 border-green-200/50">
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <Target className="h-5 w-5 text-green-600" />
                            <CardTitle className="text-sm font-medium text-green-700 dark:text-green-400">
                                Total de Deals
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold text-green-700 dark:text-green-300">
                            {totalDeals}
                        </p>
                    </CardContent>
                </Card>

                <Card className="bg-gradient-to-br from-purple-50 to-purple-100/50 dark:from-purple-950/30 dark:to-purple-900/20 border-purple-200/50">
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <DollarSign className="h-5 w-5 text-purple-600" />
                            <CardTitle className="text-sm font-medium text-purple-700 dark:text-purple-400">
                                Valor Total
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold text-purple-700 dark:text-purple-300">
                            {formatCurrency(totalValue)}
                        </p>
                    </CardContent>
                </Card>

                <Card className="bg-gradient-to-br from-orange-50 to-orange-100/50 dark:from-orange-950/30 dark:to-orange-900/20 border-orange-200/50">
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <TrendingUp className="h-5 w-5 text-orange-600" />
                            <CardTitle className="text-sm font-medium text-orange-700 dark:text-orange-400">
                                Taxa de Conversão
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold text-orange-700 dark:text-orange-300">
                            {conversionRate}%
                        </p>
                    </CardContent>
                </Card>
            </div>

            {/* Pipeline Overview */}
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Calendar className="h-5 w-5" />
                        Distribuição por Etapa
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-4">
                        {dealsByStage.map((stage) => (
                            <div
                                key={stage.value}
                                className={`p-4 rounded-lg ${stage.bgColor} text-center`}
                            >
                                <stage.icon className={`h-6 w-6 mx-auto mb-2 ${stage.textColor}`} />
                                <p className={`text-2xl font-bold ${stage.textColor}`}>
                                    {stage.count}
                                </p>
                                <p className="text-xs text-muted-foreground truncate">
                                    {stage.label}
                                </p>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>

            {/* Alerts */}
            {riskyDeals > 0 && (
                <Card className="border-red-200 bg-red-50 dark:bg-red-950/20">
                    <CardHeader className="pb-2">
                        <div className="flex items-center gap-2">
                            <AlertTriangle className="h-5 w-5 text-red-600" />
                            <CardTitle className="text-sm font-medium text-red-700 dark:text-red-400">
                                Atenção: Deals em Risco
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <p className="text-red-600 dark:text-red-400">
                            Você tem <strong>{riskyDeals}</strong> deal(s) marcado(s) como inadimplente(s).
                            Considere entrar em contato para regularizar a situação.
                        </p>
                    </CardContent>
                </Card>
            )}
        </div>
    );
}
