'use client';

/**
 * Tab de Campanhas - Gestão de Campanhas de Marketing
 */

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
    Megaphone,
    Plus,
    TrendingUp,
    Users,
    Target,
    Calendar,
    BarChart3,
} from 'lucide-react';

export function CampaignsTab() {
    // Placeholder - será conectado a um hook de campanhas no futuro
    const campaigns: Array<{
        id: string;
        name: string;
        status: 'active' | 'paused' | 'completed';
        type: string;
        leads: number;
        conversions: number;
        startDate: string;
    }> = [];

    return (
        <div className="space-y-6">
            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Campanhas Ativas
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">
                            {campaigns.filter(c => c.status === 'active').length}
                        </p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Total de Leads
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">
                            {campaigns.reduce((sum, c) => sum + c.leads, 0)}
                        </p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Conversões
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">
                            {campaigns.reduce((sum, c) => sum + c.conversions, 0)}
                        </p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">
                            Taxa de Conversão
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-3xl font-bold">0%</p>
                    </CardContent>
                </Card>
            </div>

            {/* Actions */}
            <div className="flex gap-3">
                <Button>
                    <Plus className="w-4 h-4 mr-2" />
                    Nova Campanha
                </Button>
                <Button variant="outline">
                    <Target className="w-4 h-4 mr-2" />
                    Gerador de UTM
                </Button>
            </div>

            {/* Campaigns List */}
            <Card>
                <CardHeader>
                    <CardTitle>Campanhas de Marketing</CardTitle>
                    <CardDescription>
                        Gerencie suas campanhas e acompanhe o desempenho
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    {campaigns.length === 0 ? (
                        <div className="text-center py-12 text-muted-foreground">
                            <Megaphone className="h-12 w-12 mx-auto mb-4 opacity-50" />
                            <p>Nenhuma campanha cadastrada</p>
                            <p className="text-sm">Crie campanhas para rastrear a origem dos seus leads</p>
                            <Button className="mt-4">
                                <Plus className="w-4 h-4 mr-2" />
                                Criar Primeira Campanha
                            </Button>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {campaigns.map((campaign) => (
                                <div
                                    key={campaign.id}
                                    className="flex items-center justify-between p-4 rounded-lg border hover:bg-muted/50 transition-colors"
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="p-2 rounded-lg bg-purple-500/10">
                                            <Megaphone className="h-5 w-5 text-purple-500" />
                                        </div>
                                        <div>
                                            <div className="flex items-center gap-2">
                                                <p className="font-medium">{campaign.name}</p>
                                                <Badge
                                                    variant={campaign.status === 'active' ? 'default' : 'secondary'}
                                                >
                                                    {campaign.status === 'active' ? 'Ativa' :
                                                        campaign.status === 'paused' ? 'Pausada' : 'Concluída'}
                                                </Badge>
                                            </div>
                                            <p className="text-sm text-muted-foreground">
                                                {campaign.type}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-6">
                                        <div className="text-center">
                                            <p className="text-lg font-bold">{campaign.leads}</p>
                                            <p className="text-xs text-muted-foreground">Leads</p>
                                        </div>
                                        <div className="text-center">
                                            <p className="text-lg font-bold">{campaign.conversions}</p>
                                            <p className="text-xs text-muted-foreground">Conversões</p>
                                        </div>
                                        <Button variant="ghost" size="icon">
                                            <BarChart3 className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}
