import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Plus, UserPlus, Users, ChevronDown } from "lucide-react";
import { CRMPipelineStage } from "@/types/crm";
import { toast } from "sonner";
import { createDeal } from "@/actions/crm";

export function ContactActionSelector({
    stage,
    stageConfig,
    onContactAdded,
    onExistingContactSelected
}: {
    stage: string,
    stageConfig: any,
    onContactAdded?: (dealId: string) => void,
    onExistingContactSelected?: (contactId: string, stage: string) => void
}) {
    const [showNewContactForm, setShowNewContactForm] = useState(false);
    const [showExistingContactSelector, setShowExistingContactSelector] = useState(false);

    return (
        <>
            <DropdownMenu>
                <DropdownMenuTrigger asChild>
                    <Button
                        variant="ghost"
                        size="sm"
                        className={`w-full mt-3 text-sm ${stageConfig.bgColor} ${stageConfig.textColor} hover:bg-opacity-20 border border-border/30 hover:border-current/30 transition-all duration-200 rounded-lg font-medium`}
                    >
                        <Plus className="w-4 h-4 mr-2" />
                        Adicionar Contato
                        <ChevronDown className="w-4 h-4 ml-2" />
                    </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="center" className="w-56">
                    <DropdownMenuItem onClick={() => toast.info('Funcionalidade em desenvolvimento')} className="cursor-pointer">
                        <UserPlus className="w-4 h-4 mr-2" />
                        <div className="flex flex-col">
                            <span className="font-medium">Novo Contato</span>
                            <span className="text-xs text-muted-foreground">
                                Criar um novo contato (Em breve)
                            </span>
                        </div>
                    </DropdownMenuItem>
                    <DropdownMenuItem onClick={() => toast.info('Funcionalidade em desenvolvimento')} className="cursor-pointer">
                        <Users className="w-4 h-4 mr-2" />
                        <div className="flex flex-col">
                            <span className="font-medium">Contato Existente</span>
                            <span className="text-xs text-muted-foreground">
                                Selecionar da lista (Em breve)
                            </span>
                        </div>
                    </DropdownMenuItem>
                </DropdownMenuContent>
            </DropdownMenu>
        </>
    );
}
